    16→const defaultBaseURL = "https://api.openai.com/v1"
    17→
    18→// Config holds connection parameters for an OpenAI-compatible API.
    19→type Config struct {
    20→	APIKey  string
    21→	BaseURL string // defaults to https://api.openai.com/v1
    22→}
    23→
    24→// openaiModel implements model.LLM for OpenAI-compatible chat completion APIs.
    25→type openaiModel struct {
    26→	name    string
    27→	apiKey  string
    28→	baseURL string
    29→	client  *http.Client
    30→}
    31→
    32→// NewModel creates an OpenAI-backed model.LLM.
    33→func NewModel(_ context.Context, modelName string, cfg Config) (model.LLM, error) {
    34→	if cfg.APIKey == "" {
    35→		return nil, fmt.Errorf("openai: API key is required")
    36→	}
    37→	baseURL := cfg.BaseURL
    38→	if baseURL == "" {
    39→		baseURL = defaultBaseURL
    40→	}
    41→	return &openaiModel{
    42→		name:    modelName,
    43→		apiKey:  cfg.APIKey,
    44→		baseURL: baseURL,
    45→		client:  &http.Client{},
    46→	}, nil
    47→}
    48→
    49→func (m *openaiModel) Name() string { return m.name }
    50→
    51→// GenerateContent converts the ADK request to an OpenAI chat completion request,
    52→// calls the API, and converts the response back to an LLMResponse.
    53→// Streaming is not implemented; the iterator always yields a single response.
    54→func (m *openaiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, _ bool) iter.Seq2[*model.LLMResponse, error] {
    55→	return func(yield func(*model.LLMResponse, error) bool) {
    56→		resp, err := m.doRequest(ctx, req)
    57→		if err != nil {
    58→			yield(nil, err)
    59→			return
    60→		}
    61→		yield(resp, nil)
    62→	}
    63→}
    64→
    65→// Close is a no-op; the HTTP client has no persistent state.
    66→func (m *openaiModel) Close() {}
