    68→// --- OpenAI API types ---
    69→
    70→type chatRequest struct {
    71→	Model       string        `json:"model"`
    72→	Messages    []chatMessage `json:"messages"`
    73→	Tools       []chatTool    `json:"tools,omitempty"`
    74→	Temperature *float32      `json:"temperature,omitempty"`
    75→	TopP        *float32      `json:"top_p,omitempty"`
    76→	MaxTokens   int32         `json:"max_tokens,omitempty"`
    77→	Stop        []string      `json:"stop,omitempty"`
    78→	Stream      bool          `json:"stream"`
    79→}
    80→
    81→type chatMessage struct {
    82→	Role       string     `json:"role"`
    83→	Content    string     `json:"content,omitempty"`
    84→	ToolCalls  []toolCall `json:"tool_calls,omitempty"`
    85→	ToolCallID string     `json:"tool_call_id,omitempty"`
    86→}
    87→
    88→type toolCall struct {
    89→	ID       string       `json:"id"`
    90→	Type     string       `json:"type"`
    91→	Function functionCall `json:"function"`
    92→}
    93→
    94→type functionCall struct {
    95→	Name      string `json:"name"`
    96→	Arguments string `json:"arguments"`
    97→}
    98→
    99→type chatTool struct {
   100→	Type     string       `json:"type"`
   101→	Function chatFunction `json:"function"`
   102→}
   103→
   104→type chatFunction struct {
   105→	Name        string `json:"name"`
   106→	Description string `json:"description,omitempty"`
   107→	Parameters  any    `json:"parameters,omitempty"`
   108→}
   109→
   110→type chatResponse struct {
   111→	Choices []chatChoice `json:"choices"`
   112→	Usage   *chatUsage   `json:"usage,omitempty"`
   113→	Error   *apiError    `json:"error,omitempty"`
   114→}
   115→
   116→type chatChoice struct {
   117→	Message      chatMessage `json:"message"`
   118→	FinishReason string      `json:"finish_reason"`
   119→}
   120→
   121→type chatUsage struct {
   122→	PromptTokens     int32 `json:"prompt_tokens"`
   123→	CompletionTokens int32 `json:"completion_tokens"`
   124→	TotalTokens      int32 `json:"total_tokens"`
   125→}
   126→
   127→type apiError struct {
   128→	Message string `json:"message"`
   129→	Type    string `json:"type"`
   130→	Code    string `json:"code"`
   131→}
