    35→// TODO: test coverage
    36→type geminiModel struct {
    37→	client             *genai.Client
    38→	name               string
    39→	versionHeaderValue string
    40→}
    41→
    42→// NewModel returns [model.LLM], backed by the Gemini API.
    43→//
    44→// It uses the provided context and configuration to initialize the underlying
    45→// [genai.Client]. The modelName specifies which Gemini model to target
    46→// (e.g., "gemini-2.5-flash").
    47→//
    48→// An error is returned if the [genai.Client] fails to initialize.
    49→func NewModel(ctx context.Context, modelName string, cfg *genai.ClientConfig) (model.LLM, error) {
    50→	client, err := genai.NewClient(ctx, cfg)
    51→	if err != nil {
    52→		return nil, err
    53→	}
    54→
    55→	// Create header value once, when the model is created
    56→	headerValue := fmt.Sprintf("google-adk/%s gl-go/%s", version.Version,
    57→		strings.TrimPrefix(runtime.Version(), "go"))
    58→
    59→	return &geminiModel{
    60→		name:               modelName,
    61→		client:             client,
    62→		versionHeaderValue: headerValue,
    63→	}, nil
    64→}
    65→
    66→func (m *geminiModel) Name() string {
    67→	return m.name
    68→}
    69→
    70→// GenerateContent calls the underlying model.
    71→func (m *geminiModel) GenerateContent(ctx context.Context, req *model.LLMRequest, stream bool) iter.Seq2[*model.LLMResponse, error] {
    72→	m.maybeAppendUserContent(req)
    73→	if req.Config == nil {
    74→		req.Config = &genai.GenerateContentConfig{}
    75→	}
    76→	if req.Config.HTTPOptions == nil {
    77→		req.Config.HTTPOptions = &genai.HTTPOptions{}
    78→	}
    79→	if req.Config.HTTPOptions.Headers == nil {
    80→		req.Config.HTTPOptions.Headers = make(http.Header)
    81→	}
    82→	m.addHeaders(req.Config.HTTPOptions.Headers)
    83→
    84→	if stream {
    85→		return m.generateStream(ctx, req)
    86→	}
    87→
    88→	return func(yield func(*model.LLMResponse, error) bool) {
    89→		resp, err := m.generate(ctx, req)
    90→		yield(resp, err)
    91→	}
    92→}
    93→
    94→// addHeaders sets the x-goog-api-client and user-agent headers
    95→func (m *geminiModel) addHeaders(headers http.Header) {
    96→	headers.Set("x-goog-api-client", m.versionHeaderValue)
    97→	headers.Set("user-agent", m.versionHeaderValue)
    98→}
    99→
   100→// generate calls the model synchronously returning result from the first candidate.
   101→func (m *geminiModel) generate(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   102→	resp, err := m.client.Models.GenerateContent(ctx, m.name, req.Contents, req.Config)
   103→	if err != nil {
   104→		return nil, fmt.Errorf("failed to call model: %w", err)
   105→	}
   106→	if len(resp.Candidates) == 0 {
   107→		// shouldn't happen?
   108→		return nil, fmt.Errorf("empty response")
   109→	}
   110→	return converters.Genai2LLMResponse(resp), nil
   111→}
   112→
   113→// generateStream returns a stream of responses from the model.
   114→func (m *geminiModel) generateStream(ctx context.Context, req *model.LLMRequest) iter.Seq2[*model.LLMResponse, error] {
   115→	aggregator := llminternal.NewStreamingResponseAggregator()
   116→
   117→	return func(yield func(*model.LLMResponse, error) bool) {
   118→		for resp, err := range m.client.Models.GenerateContentStream(ctx, m.name, req.Contents, req.Config) {
   119→			if err != nil {
   120→				yield(nil, err)
   121→				return
   122→			}
   123→			for llmResponse, err := range aggregator.ProcessResponse(ctx, resp) {
   124→				if !yield(llmResponse, err) {
   125→					return // Consumer stopped
   126→				}
   127→			}
   128→		}
   129→		if closeResult := aggregator.Close(); closeResult != nil {
   130→			yield(closeResult, nil)
   131→		}
   132→	}
   133→}
   134→
   135→// maybeAppendUserContent appends a user content, so that model can continue to output.
   136→func (m *geminiModel) maybeAppendUserContent(req *model.LLMRequest) {
   137→	if len(req.Contents) == 0 {
   138→		req.Contents = append(req.Contents, genai.NewContentFromText("Handle the requests as specified in the System Instruction.", "user"))
   139→	}
   140→
   141→	if last := req.Contents[len(req.Contents)-1]; last != nil && last.Role != "user" {
   142→		req.Contents = append(req.Contents, genai.NewContentFromText("Continue processing previous requests as instructed. Exit or provide a summary if no more outputs are needed.", "user"))
   143→	}
   144→}
