   146→func (m *geminiModel) GetGoogleLLMVariant() genai.Backend {
   147→	if m == nil || m.client == nil {
   148→		return genai.BackendUnspecified
   149→	}
   150→	return m.client.ClientConfig().Backend
   151→}
