    17→// different types of `genai` tools cannot be used together.
    18→package agenttool
    19→
    20→import (
    21→	"encoding/json"
    22→	"fmt"
    23→	"strings"
    24→
    25→	"google.golang.org/genai"
    26→
    27→	"google.golang.org/adk/agent"
    28→	"google.golang.org/adk/artifact"
    29→	"google.golang.org/adk/internal/llminternal"
    30→	"google.golang.org/adk/internal/utils"
    31→	"google.golang.org/adk/memory"
    32→	"google.golang.org/adk/model"
    33→	"google.golang.org/adk/runner"
    34→	"google.golang.org/adk/session"
    35→	"google.golang.org/adk/tool"
    36→)
    37→
    38→// agentTool implements a tool that allows an agent to call another agent.
    39→type agentTool struct {
    40→	agent             agent.Agent
    41→	skipSummarization bool
    42→}
    43→
    44→// Config holds the configuration for an agent tool.
    45→type Config struct {
    46→	// SkipSummarization, if true, will cause the agent to skip summarization
    47→	// after the sub-agent finishes execution.
    48→	SkipSummarization bool
    49→}
    50→
    51→// New creates a new agent tool.
    52→// If cfg is nil, skipSummarization defaults to false.
    53→func New(agent agent.Agent, cfg *Config) tool.Tool {
    54→	if cfg == nil {
    55→		return &agentTool{
    56→			agent:             agent,
    57→			skipSummarization: false,
    58→		}
    59→	}
    60→	return &agentTool{
    61→		agent:             agent,
    62→		skipSummarization: cfg.SkipSummarization,
    63→	}
    64→}
    65→
    66→// Name implements tool.Tool.
    67→func (t *agentTool) Name() string {
    68→	return t.agent.Name()
    69→}
    70→
    71→// Description implements tool.Tool.
    72→func (t *agentTool) Description() string {
    73→	return t.agent.Description()
    74→}
    75→
    76→// IsLongRunning implements tool.Tool.
    77→func (t *agentTool) IsLongRunning() bool {
    78→	return false
    79→}
    80→
    81→// Declaration returns the function declaration for the wrapped agent.
    82→// It generates a function declaration based on the agent's input schema.
    83→// If the agent does not have an input schema, a default schema with a
    84→// "request" string parameter is used.
    85→func (t *agentTool) Declaration() *genai.FunctionDeclaration {
    86→	decl := &genai.FunctionDeclaration{
    87→		Name:        t.Name(),
    88→		Description: t.Description(),
    89→	}
    90→
    91→	var agentInputSchema *genai.Schema
    92→	llmAgent, ok := t.agent.(llminternal.Agent)
    93→	if ok && llmAgent != nil {
    94→		// TODO - understand what build_function_declaration does in python and apply if needed.
    95→		internalLlmAgent, ok := t.agent.(llminternal.Agent)
    96→		if !ok {
    97→			return nil
    98→		}
    99→		agentInputSchema = llminternal.Reveal(internalLlmAgent).InputSchema
   100→	}
   101→
   102→	if agentInputSchema != nil {
   103→		decl.Parameters = agentInputSchema
   104→	} else {
   105→		decl.Parameters = &genai.Schema{
   106→			Type: "OBJECT",
   107→			Properties: map[string]*genai.Schema{
   108→				"request": {Type: "STRING"},
   109→			},
   110→			Required: []string{"request"},
   111→		}
   112→	}
   113→	// TODO - understand how _api_variant affects response type.
   114→	return decl
   115→}
   116→
   117→// Run executes the wrapped agent with the provided arguments.
   118→// It creates a new session for the sub-agent, runs the agent, and returns
   119→// the final result.
   120→func (t *agentTool) Run(toolCtx tool.Context, args any) (map[string]any, error) {
   121→	margs, ok := args.(map[string]any)
   122→	if !ok {
   123→		return nil, fmt.Errorf("agentTool expects map[string]any arguments, got %T", args)
   124→	}
   125→
   126→	if t.skipSummarization {
   127→		if actions := toolCtx.Actions(); actions != nil {
   128→			actions.SkipSummarization = true
   129→		}
   130→	}
   131→
   132→	var agentInputSchema *genai.Schema
   133→	llmAgent, ok := t.agent.(llminternal.Agent)
   134→	isLllmAgent := (ok && llmAgent != nil)
   135→	if isLllmAgent {
   136→		internalLlmAgent, ok := t.agent.(llminternal.Agent)
   137→		if !ok {
   138→			return nil, fmt.Errorf("internal error: failed to convert to llm agent")
   139→		}
   140→		agentInputSchema = llminternal.Reveal(internalLlmAgent).InputSchema
   141→	}
   142→
   143→	var content *genai.Content
   144→	var err error
   145→	if agentInputSchema != nil {
   146→		if err = utils.ValidateMapOnSchema(margs, agentInputSchema, true); err != nil {
   147→			return nil, fmt.Errorf("argument validation failed for agent %s: %w", t.agent.Name(), err)
   148→		}
   149→		jsonData, err := json.Marshal(margs)
   150→		if err != nil {
   151→			return nil, fmt.Errorf("error serializing tool arguments for agent %s: %w", t.agent.Name(), err)
   152→		}
   153→		content = genai.NewContentFromText(string(jsonData), genai.RoleUser)
   154→	} else {
   155→		input, ok := margs["request"]
   156→		if !ok {
   157→			return nil, fmt.Errorf("missing required argument 'request' for agent %s", t.agent.Name())
   158→		}
   159→		inputText, ok := input.(string)
   160→		if !ok {
   161→			// Try to convert to string if not already one
   162→			inputText = fmt.Sprint(input)
   163→		}
   164→		content = genai.NewContentFromText(inputText, genai.RoleUser)
   165→	}
   166→
   167→	sessionService := session.InMemoryService()
   168→
   169→	r, err := runner.New(runner.Config{
   170→		AppName:        t.agent.Name(),
   171→		Agent:          t.agent,
   172→		SessionService: sessionService,
   173→		// TODO - use forwarding_artifact_service as in python.
   174→		ArtifactService: artifact.InMemoryService(),
   175→		MemoryService:   memory.InMemoryService(),
   176→	})
   177→	if err != nil {
   178→		return nil, fmt.Errorf("failed to create runner")
   179→	}
   180→
   181→	stateMap := make(map[string]any)
   182→
   183→	for k, v := range toolCtx.State().All() {
   184→		// Filter out adk internal states.
   185→		if !strings.HasPrefix(k, "_adk") {
   186→			stateMap[k] = v
   187→		}
   188→	}
   189→
   190→	subSession, err := sessionService.Create(toolCtx, &session.CreateRequest{
   191→		AppName: t.agent.Name(),
   192→		UserID:  toolCtx.UserID(),
   193→		State:   stateMap,
   194→	})
   195→	if err != nil {
   196→		return nil, fmt.Errorf("failed to create session for sub-agent %s: %w", t.agent.Name(), err)
   197→	}
   198→
   199→	// TODO(dpasiukevich): verify agent loop termination.
   200→	eventCh := r.Run(toolCtx, subSession.Session.UserID(), subSession.Session.ID(), content, agent.RunConfig{
   201→		StreamingMode: agent.StreamingModeSSE,
   202→	})
   203→
   204→	var lastEvent *session.Event
   205→	for event, err := range eventCh {
   206→		if err != nil {
   207→			return nil, fmt.Errorf("error during execution of sub-agent %s: %w", t.agent.Name(), err)
   208→		}
   209→		if event.ErrorCode != "" || event.ErrorMessage != "" {
   210→			return nil, fmt.Errorf("error from sub-agent %q (code: %q, message: %q)", t.agent.Name(), event.ErrorCode, event.ErrorMessage)
   211→		}
   212→		if event.LLMResponse.Content != nil {
   213→			lastEvent = event
   214→		}
   215→	}
   216→
   217→	if lastEvent == nil {
   218→		return map[string]any{}, nil
   219→	}
   220→
   221→	lastContent := lastEvent.LLMResponse.Content
   222→	var textParts []string
   223→	for _, part := range lastContent.Parts {
   224→		if part != nil && part.Text != "" {
   225→			textParts = append(textParts, part.Text)
   226→		}
   227→	}
   228→	outputText := strings.Join(textParts, "\n")
   229→
   230→	if outputText == "" {
   231→		return map[string]any{}, nil
   232→	}
   233→	if isLllmAgent {
   234→		internalLlmAgent, ok := t.agent.(llminternal.Agent)
   235→		if !ok {
   236→			return nil, fmt.Errorf("internal error: failed to convert to llm agent")
   237→		}
   238→		if agentOutputSchema := llminternal.Reveal(internalLlmAgent).OutputSchema; agentOutputSchema != nil {
   239→			// Assuming schemautils.ValidateOutputSchema parses the JSON string outputText
   240→			// and validates it against the agentOutputSchema, returning a map[string]any.
   241→			parsedOutput, err := utils.ValidateOutputSchema(outputText, agentOutputSchema)
   242→			if err != nil {
   243→				return nil, fmt.Errorf("output validation failed for sub-agent %s: %w", t.agent.Name(), err)
   244→			}
   245→			return parsedOutput, nil
   246→		}
   247→	}
   248→
   249→	return map[string]any{"result": outputText}, nil
   250→}
   251→
   252→// ProcessRequest adds the agent tool's function declaration to the LLM request.
   253→func (t *agentTool) ProcessRequest(ctx tool.Context, req *model.LLMRequest) error {
   254→	// TODO extract this function somewhere else, simillar operations are done for
   255→	// other tools with function declaration.
   256→	if req.Tools == nil {
   257→		req.Tools = make(map[string]any)
   258→	}
   259→
   260→	name := t.Name()
   261→	if _, ok := req.Tools[name]; ok {
   262→		return fmt.Errorf("duplicate tool: %q", name)
   263→	}
   264→	req.Tools[name] = t
   265→
   266→	if req.Config == nil {
   267→		req.Config = &genai.GenerateContentConfig{}
   268→	}
   269→	if decl := t.Declaration(); decl == nil {
   270→		return nil
   271→	}
   272→	var funcTool *genai.Tool
   273→	for _, tool := range req.Config.Tools {
   274→		if tool != nil && tool.FunctionDeclarations != nil {
   275→			funcTool = tool
   276→			break
   277→		}
   278→	}
   279→	if funcTool == nil {
   280→		req.Config.Tools = append(req.Config.Tools, &genai.Tool{
   281→			FunctionDeclarations: []*genai.FunctionDeclaration{t.Declaration()},
   282→		})
   283→	} else {
   284→		funcTool.FunctionDeclarations = append(funcTool.FunctionDeclarations, t.Declaration())
   285→	}
   286→	return nil
   287→}
