   204→		var text string
   205→		for _, p := range req.Config.SystemInstruction.Parts {
   206→			if p.Text != "" {
   207→				text += p.Text
   208→			}
   209→		}
   210→		if text != "" {
   211→			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   212→		}
   213→	}
   214→
   215→	// Conversation contents.
   216→	for _, c := range req.Contents {
   217→		role := mapRole(c.Role)
   218→
   219→		// Check each part: could be text, function_call, or function_response.
   220→		for _, p := range c.Parts {
   221→			switch {
   222→			case p.FunctionCall != nil:
   223→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   224→				msgs = append(msgs, chatMessage{
   225→					Role: "assistant",
   226→					ToolCalls: []toolCall{{
   227→						ID:   p.FunctionCall.ID,
   228→						Type: "function",
   229→						Function: functionCall{
   230→							Name:      p.FunctionCall.Name,
   231→							Arguments: string(argsJSON),
   232→						},
   233→					}},
   234→				})
   235→			case p.FunctionResponse != nil:
   236→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   237→				msgs = append(msgs, chatMessage{
   238→					Role:       "tool",
   239→					Content:    string(respJSON),
   240→					ToolCallID: p.FunctionResponse.ID,
   241→				})
   242→			case p.Text != "":
   243→				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   244→			}
   245→		}
   246→	}
   247→
   248→	// Merge consecutive assistant messages with tool_calls.
   249→	msgs = mergeAssistantToolCalls(msgs)
   250→
   251→	return msgs
   252→}
   253→
   254→// mergeAssistantToolCalls combines adjacent assistant messages that each have
   255→// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   256→// one message rather than separate messages.
   257→func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   258→	if len(msgs) == 0 {
   259→		return msgs
   260→	}
   261→	var merged []chatMessage
   262→	for _, msg := range msgs {
   263→		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   264→			prev := &merged[len(merged)-1]
   265→			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   266→				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   267→				continue
   268→			}
   269→		}
   270→		merged = append(merged, msg)
   271→	}
   272→	return merged
   273→}
   274→
   275→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   276→func convertTools(req *model.LLMRequest) []chatTool {
   277→	if req.Config == nil || len(req.Config.Tools) == 0 {
   278→		return nil
   279→	}
   280→
   281→	var tools []chatTool
   282→	for _, t := range req.Config.Tools {
   283→		for _, fd := range t.FunctionDeclarations {
   284→			ct := chatTool{
   285→				Type: "function",
   286→				Function: chatFunction{
   287→					Name:        fd.Name,
   288→					Description: fd.Description,
   289→				},
   290→			}
   291→			if fd.Parameters != nil {
   292→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   293→			}
   294→			tools = append(tools, ct)
   295→		}
   296→	}
   297→	return tools
   298→}
   299→
   300→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   301→// the OpenAI function parameters format (JSON Schema).
   302→func schemaToMap(s *genai.Schema) map[string]any {
   303→	m := map[string]any{}
   304→	if s.Type != "" {
   305→		m["type"] = strings.ToLower(string(s.Type))
   306→	}
   307→	if s.Description != "" {
   308→		m["description"] = s.Description
   309→	}
   310→	if len(s.Enum) > 0 {
   311→		m["enum"] = s.Enum
   312→	}
   313→	if s.Items != nil {
   314→		m["items"] = schemaToMap(s.Items)
   315→	}
   316→	if len(s.Properties) > 0 {
   317→		props := map[string]any{}
   318→		for k, v := range s.Properties {
   319→			props[k] = schemaToMap(v)
   320→		}
   321→		m["properties"] = props
   322→	}
   323→	if len(s.Required) > 0 {
   324→		m["required"] = s.Required
   325→	}
   326→	return m
   327→}
   328→
   329→// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   330→func convertResponse(resp *chatResponse) *model.LLMResponse {
   331→	llmResp := &model.LLMResponse{
   332→		TurnComplete: true,
   333→	}
   334→
   335→	if len(resp.Choices) == 0 {
   336→		llmResp.Content = genai.NewContentFromText("", "model")
   337→		return llmResp
   338→	}
   339→
   340→	choice := resp.Choices[0]
   341→	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   342→
   343→	content := &genai.Content{Role: "model"}
   344→
   345→	// Text content.
   346→	if choice.Message.Content != "" {
   347→		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   348→	}
   349→
   350→	// Tool calls.
   351→	for _, tc := range choice.Message.ToolCalls {
   352→		var args map[string]any
   353→		if tc.Function.Arguments != "" {
   354→			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   355→		}
   356→		content.Parts = append(content.Parts, &genai.Part{
   357→			FunctionCall: &genai.FunctionCall{
   358→				ID:   tc.ID,
   359→				Name: tc.Function.Name,
   360→				Args: args,
   361→			},
   362→		})
   363→	}
   364→
   365→	llmResp.Content = content
   366→
   367→	if resp.Usage != nil {
   368→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   369→			PromptTokenCount:     resp.Usage.PromptTokens,
   370→			CandidatesTokenCount: resp.Usage.CompletionTokens,
   371→			TotalTokenCount:      resp.Usage.TotalTokens,
   372→		}
   373→	}
   374→
   375→	return llmResp
   376→}
   377→
   378→func mapRole(role string) string {
   379→	switch role {
   380→	case "model":
   381→		return "assistant"
   382→	default:
   383→		return role
   384→	}
   385→}
   386→
   387→func mapFinishReason(reason string) genai.FinishReason {
   388→	switch reason {
   389→	case "stop":
   390→		return genai.FinishReasonStop
   391→	case "length":
   392→		return genai.FinishReasonMaxTokens
   393→	case "tool_calls":
   394→		return genai.FinishReasonStop
   395→	case "content_filter":
   396→		return genai.FinishReasonSafety
   397→	default:
   398→		return genai.FinishReasonOther
   399→	}
   400→}
