    69→// --- OpenAI API types ---
    70→
    71→type webSearchOptions struct{}
    72→
    73→type chatRequest struct {
    74→	Model            string            `json:"model"`
    75→	Messages         []chatMessage     `json:"messages"`
    76→	Tools            []chatTool        `json:"tools,omitempty"`
    77→	Temperature      *float32          `json:"temperature,omitempty"`
    78→	TopP             *float32          `json:"top_p,omitempty"`
    79→	MaxTokens        int32             `json:"max_tokens,omitempty"`
    80→	Stop             []string          `json:"stop,omitempty"`
