   135→}
   136→
   137→// --- request/response conversion ---
   138→
   139→func (m *openaiModel) doRequest(ctx context.Context, req *model.LLMRequest) (*model.LLMResponse, error) {
   140→	msgs := convertContents(req)
   141→	tools := convertTools(req)
   142→
   143→	chatReq := chatRequest{
   144→		Model:    m.name,
   145→		Messages: msgs,
   146→		Tools:    tools,
   147→		Stream:   false,
   148→	}
   149→
   150→	if req.Config != nil {
   151→		chatReq.Temperature = req.Config.Temperature
   152→		chatReq.TopP = req.Config.TopP
   153→		if req.Config.MaxOutputTokens > 0 {
   154→			chatReq.MaxTokens = req.Config.MaxOutputTokens
   155→		}
   156→		if len(req.Config.StopSequences) > 0 {
   157→			chatReq.Stop = req.Config.StopSequences
   158→		}
   159→	}
   160→
   161→	if hasWebSearch(req) {
   162→		chatReq.WebSearchOptions = &webSearchOptions{}
   163→	}
   164→
   165→	body, err := json.Marshal(chatReq)
   166→	if err != nil {
   167→		return nil, fmt.Errorf("openai: marshal request: %w", err)
   168→	}
   169→
   170→	httpReq, err := http.NewRequestWithContext(ctx, http.MethodPost, m.baseURL+"/chat/completions", bytes.NewReader(body))
   171→	if err != nil {
   172→		return nil, fmt.Errorf("openai: create http request: %w", err)
   173→	}
   174→	httpReq.Header.Set("Content-Type", "application/json")
   175→	httpReq.Header.Set("Authorization", "Bearer "+m.apiKey)
   176→
   177→	httpResp, err := m.client.Do(httpReq)
   178→	if err != nil {
   179→		return nil, fmt.Errorf("openai: http request: %w", err)
   180→	}
   181→	defer httpResp.Body.Close()
   182→
   183→	respBody, err := io.ReadAll(httpResp.Body)
   184→	if err != nil {
   185→		return nil, fmt.Errorf("openai: read response: %w", err)
   186→	}
   187→
   188→	if httpResp.StatusCode != http.StatusOK {
   189→		return nil, fmt.Errorf("openai: API returned status %d: %s", httpResp.StatusCode, string(respBody))
   190→	}
