   205→// convertContents transforms ADK genai.Content messages into OpenAI chat messages.
   206→func convertContents(req *model.LLMRequest) []chatMessage {
   207→	var msgs []chatMessage
   208→
   209→	// System instruction.
   210→	if req.Config != nil && req.Config.SystemInstruction != nil {
   211→		var text string
   212→		for _, p := range req.Config.SystemInstruction.Parts {
   213→			if p.Text != "" {
   214→				text += p.Text
   215→			}
   216→		}
   217→		if text != "" {
   218→			msgs = append(msgs, chatMessage{Role: "system", Content: text})
   219→		}
   220→	}
   221→
   222→	// Conversation contents.
   223→	for _, c := range req.Contents {
   224→		role := mapRole(c.Role)
   225→
   226→		// Check each part: could be text, function_call, or function_response.
   227→		for _, p := range c.Parts {
   228→			switch {
   229→			case p.FunctionCall != nil:
   230→				argsJSON, _ := json.Marshal(p.FunctionCall.Args)
   231→				msgs = append(msgs, chatMessage{
   232→					Role: "assistant",
   233→					ToolCalls: []toolCall{{
   234→						ID:   p.FunctionCall.ID,
   235→						Type: "function",
   236→						Function: functionCall{
   237→							Name:      p.FunctionCall.Name,
   238→							Arguments: string(argsJSON),
   239→						},
   240→					}},
   241→				})
   242→			case p.FunctionResponse != nil:
   243→				respJSON, _ := json.Marshal(p.FunctionResponse.Response)
   244→				msgs = append(msgs, chatMessage{
   245→					Role:       "tool",
   246→					Content:    string(respJSON),
   247→					ToolCallID: p.FunctionResponse.ID,
   248→				})
   249→			case p.Text != "":
   250→				msgs = append(msgs, chatMessage{Role: role, Content: p.Text})
   251→			}
   252→		}
   253→	}
   254→
   255→	// Merge consecutive assistant messages with tool_calls.
   256→	msgs = mergeAssistantToolCalls(msgs)
   257→
   258→	return msgs
   259→}
   260→
   261→// mergeAssistantToolCalls combines adjacent assistant messages that each have
   262→// tool_calls into a single message, as OpenAI expects multiple tool_calls in
   263→// one message rather than separate messages.
   264→func mergeAssistantToolCalls(msgs []chatMessage) []chatMessage {
   265→	if len(msgs) == 0 {
   266→		return msgs
   267→	}
   268→	var merged []chatMessage
   269→	for _, msg := range msgs {
   270→		if msg.Role == "assistant" && len(msg.ToolCalls) > 0 && len(merged) > 0 {
   271→			prev := &merged[len(merged)-1]
   272→			if prev.Role == "assistant" && len(prev.ToolCalls) > 0 {
   273→				prev.ToolCalls = append(prev.ToolCalls, msg.ToolCalls...)
   274→				continue
   275→			}
   276→		}
   277→		merged = append(merged, msg)
   278→	}
   279→	return merged
   280→}
   281→
   282→// hasWebSearch checks whether the request contains a GoogleSearch tool marker,
   283→// indicating the caller wants web search capability.
   284→func hasWebSearch(req *model.LLMRequest) bool {
   285→	if req.Config == nil {
   286→		return false
   287→	}
   288→	for _, t := range req.Config.Tools {
   289→		if t != nil && t.GoogleSearch != nil {
   290→			return true
   291→		}
   292→	}
   293→	return false
   294→}
   295→
   296→// convertTools transforms ADK genai.Tool definitions into OpenAI tool format.
   297→func convertTools(req *model.LLMRequest) []chatTool {
   298→	if req.Config == nil || len(req.Config.Tools) == 0 {
   299→		return nil
   300→	}
   301→
   302→	var tools []chatTool
   303→	for _, t := range req.Config.Tools {
   304→		if t.GoogleSearch != nil {
   305→			continue
   306→		}
   307→		for _, fd := range t.FunctionDeclarations {
   308→			ct := chatTool{
   309→				Type: "function",
   310→				Function: chatFunction{
   311→					Name:        fd.Name,
   312→					Description: fd.Description,
   313→				},
   314→			}
   315→			if fd.Parameters != nil {
   316→				ct.Function.Parameters = schemaToMap(fd.Parameters)
   317→			}
   318→			tools = append(tools, ct)
   319→		}
   320→	}
   321→	return tools
   322→}
   323→
   324→// schemaToMap converts a genai.Schema to a JSON-serialisable map that matches
   325→// the OpenAI function parameters format (JSON Schema).
   326→func schemaToMap(s *genai.Schema) map[string]any {
   327→	m := map[string]any{}
   328→	if s.Type != "" {
   329→		m["type"] = strings.ToLower(string(s.Type))
   330→	}
   331→	if s.Description != "" {
   332→		m["description"] = s.Description
   333→	}
   334→	if len(s.Enum) > 0 {
   335→		m["enum"] = s.Enum
   336→	}
   337→	if s.Items != nil {
   338→		m["items"] = schemaToMap(s.Items)
   339→	}
   340→	if len(s.Properties) > 0 {
   341→		props := map[string]any{}
   342→		for k, v := range s.Properties {
   343→			props[k] = schemaToMap(v)
   344→		}
   345→		m["properties"] = props
   346→	}
   347→	if len(s.Required) > 0 {
   348→		m["required"] = s.Required
   349→	}
   350→	return m
   351→}
   352→
   353→// convertResponse transforms an OpenAI chat completion response into an ADK LLMResponse.
   354→func convertResponse(resp *chatResponse) *model.LLMResponse {
   355→	llmResp := &model.LLMResponse{
   356→		TurnComplete: true,
   357→	}
   358→
   359→	if len(resp.Choices) == 0 {
   360→		llmResp.Content = genai.NewContentFromText("", "model")
   361→		return llmResp
   362→	}
   363→
   364→	choice := resp.Choices[0]
   365→	llmResp.FinishReason = mapFinishReason(choice.FinishReason)
   366→
   367→	content := &genai.Content{Role: "model"}
   368→
   369→	// Text content.
   370→	if choice.Message.Content != "" {
   371→		content.Parts = append(content.Parts, &genai.Part{Text: choice.Message.Content})
   372→	}
   373→
   374→	// Tool calls.
   375→	for _, tc := range choice.Message.ToolCalls {
   376→		var args map[string]any
   377→		if tc.Function.Arguments != "" {
   378→			_ = json.Unmarshal([]byte(tc.Function.Arguments), &args)
   379→		}
   380→		content.Parts = append(content.Parts, &genai.Part{
   381→			FunctionCall: &genai.FunctionCall{
   382→				ID:   tc.ID,
   383→				Name: tc.Function.Name,
   384→				Args: args,
   385→			},
   386→		})
   387→	}
   388→
   389→	llmResp.Content = content
   390→
   391→	if resp.Usage != nil {
   392→		llmResp.UsageMetadata = &genai.GenerateContentResponseUsageMetadata{
   393→			PromptTokenCount:     resp.Usage.PromptTokens,
   394→			CandidatesTokenCount: resp.Usage.CompletionTokens,
   395→			TotalTokenCount:      resp.Usage.TotalTokens,
   396→		}
   397→	}
   398→
   399→	return llmResp
   400→}
   401→
   402→func mapRole(role string) string {
   403→	switch role {
   404→	case "model":
   405→		return "assistant"
   406→	default:
   407→		return role
   408→	}
   409→}
   410→
   411→func mapFinishReason(reason string) genai.FinishReason {
   412→	switch reason {
   413→	case "stop":
   414→		return genai.FinishReasonStop
   415→	case "length":
   416→		return genai.FinishReasonMaxTokens
   417→	case "tool_calls":
   418→		return genai.FinishReasonStop
   419→	case "content_filter":
   420→		return genai.FinishReasonSafety
   421→	default:
   422→		return genai.FinishReasonOther
   423→	}
   424→}
